            'sku_part_number': sku.skuPartNumber | d('Unknown SKU'),
            'display_name': sku.skuPartNumber | d('Unknown SKU'),
            'consumed_units': sku.consumedUnits | d(0) | int,
            'enabled_units': sku.prepaidUnits.enabled | d(0) | int
        }}) %}
    {% endif %}
{% endfor %}

{% set office_map = {} %}
