    {% set upn = (row['User Principal Name'] | d(row['User Principal Name ']) | d(row.userPrincipalName) | d(row['UPN']) | d('')) | lower %}
    {% if upn %}{% set _ = office_map.update({upn: row}) %}{% endif %}
