{% endfor %}

{% set stale_cutoff = UTILS.now() | convert_from_epoch | time_delta(days=-(CTX.stale_days | int)) | format_datetime('%Y-%m-%dT%H:%M:%S') %}
{% set recent_cutoff = UTILS.now() | convert_from_epoch | time_delta(days=-(CTX.report_window_days | int)) | format_datetime('%Y-%m-%dT%H:%M:%S') %}

{% set data = {
    'tenant_name': CTX.tenant_name,
    'report_period': CTX.report_period,
    'stale_days': CTX.stale_days | int,
    'generated_at': UTILS.now() | convert_from_epoch | format_datetime('%Y-%m-%d %H:%M UTC'),
    'notes': [
        'Focused on the centrexIT tenant only for this first build.',
        'Workload usage reports are delayed by Microsoft and should be treated as operational reporting, not real-time telemetry.',
        'User baseline currently pulls up to 500 users in one pass; expand paging if tenant growth exceeds that.'
    ],
    'summary': {},
    'pricing_summary': {},
    'workload_summary': {},
    'user_rows': [],
    'stale_rows': [],
    'license_rows': [],
    'recommendation_rows': []
} %}
{% set counters = namespace(total=0, enabled=0, licensed=0, active=0, low=0, stale=0, excluded=0, no_workload=0, unlicensed=0) %}
{% set workload = namespace(office=0, email=0, teams=0, onedrive=0, sharepoint=0, m365app=0) %}
{% set price_map = {
    'AAD_PREMIUM_P2': {'monthly': 9.00, 'source': 'Microsoft Entra ID P2'},
    'Microsoft_365_E3_(no_Teams)': {'monthly': 27.45, 'source': 'Microsoft 365 E3 (no Teams)'},
    'Microsoft_365_Copilot': {'monthly': 30.00, 'source': 'Microsoft 365 Copilot'},
    'POWER_BI_STANDARD': {'monthly': 14.00, 'source': 'Power BI Pro'},
    'PBI_PREMIUM_PER_USER': {'monthly': 24.00, 'source': 'Power BI Premium Per User'},
    'PROJECTPREMIUM': {'monthly': 55.00, 'source': 'Planner and Project Plan 5'},
    'FLOW_FREE': {'monthly': 0.00, 'source': 'Free'},
    'Microsoft_Teams_Enterprise_New': {'monthly': 8.55, 'source': 'Microsoft Teams Enterprise'}
} %}
{% set priced_totals = namespace(monthly=0, stale_monthly=0, low_monthly=0, no_workload_monthly=0, priced_assignments=0, total_assignments=0) %}
{% set license_map = {} %}

{% for user in users %}
    {% set upn = (user.userPrincipalName | d(user.mail) | d('')) | lower %}
    {% if not upn %}{% continue %}{% endif %}
    {% set counters.total = counters.total + 1 %}
    {% set account_enabled = user.accountEnabled | d(true) %}
    {% if account_enabled %}{% set counters.enabled = counters.enabled + 1 %}{% endif %}
    {% set assigned_licenses = user.assignedLicenses | d([]) %}
    {% set assigned_plans = user.assignedPlans | d([]) %}
    {% set license_names = [] %}
    {% for lic in assigned_licenses %}
        {% set sku_id = lic.skuId | d('') %}
        {% if sku_id in sku_map %}
            {% set _ = license_names.append(sku_map[sku_id].sku_part_number) %}
        {% elif sku_id %}
            {% set _ = license_names.append(sku_id) %}
        {% endif %}
    {% endfor %}
    {% set licensed = license_names | length > 0 %}
    {% if licensed %}{% set counters.licensed = counters.licensed + 1 %}{% else %}{% set counters.unlicensed = counters.unlicensed + 1 %}{% endif %}
    {% set cost_ref = namespace(monthly=0.0, priced_licenses=[], unpriced_licenses=[]) %}
    {% for license_name in license_names %}
        {% set priced_totals.total_assignments = priced_totals.total_assignments + 1 %}
        {% if license_name in price_map %}
            {% set cost_ref.monthly = cost_ref.monthly + price_map[license_name].monthly %}
            {% set priced_totals.monthly = priced_totals.monthly + price_map[license_name].monthly %}
            {% set priced_totals.priced_assignments = priced_totals.priced_assignments + 1 %}
            {% set _ = cost_ref.priced_licenses.append(license_name) %}
        {% else %}
            {% set _ = cost_ref.unpriced_licenses.append(license_name) %}
        {% endif %}
    {% endfor %}

    {% set excluded_ref = namespace(value=false) %}
    {% for pattern in CTX.exclusion_patterns | d([]) %}
        {% if pattern and (pattern | lower) in upn %}
            {% set excluded_ref.value = true %}
        {% endif %}
    {% endfor %}
    {% if excluded_ref.value %}{% set counters.excluded = counters.excluded + 1 %}{% endif %}

    {% set sign_in = user.signInActivity | d({}) %}
    {% set last_success = sign_in.lastSuccessfulSignInDateTime | d('') %}
    {% set recent_signin = last_success and (last_success[:19] >= recent_cutoff[:19]) %}
    {% set stale = licensed and account_enabled and (not last_success or last_success[:19] < stale_cutoff[:19]) %}
    {% if stale %}{% set counters.stale = counters.stale + 1 %}{% endif %}

    {% set office_active = upn in office_map and (office_map[upn]['Last Activity Date'] | d('')) != '' %}
    {% set email_active = upn in email_map and (email_map[upn]['Last Activity Date'] | d('')) != '' %}
    {% set teams_active = upn in teams_map and (teams_map[upn]['Last Activity Date'] | d('')) != '' %}
    {% set onedrive_active = upn in onedrive_map and (onedrive_map[upn]['Last Activity Date'] | d('')) != '' %}
    {% set sharepoint_active = upn in sharepoint_map and (sharepoint_map[upn]['Last Activity Date'] | d('')) != '' %}
    {% set m365app_active = upn in m365app_map and (m365app_map[upn]['Last Activity Date'] | d('')) != '' %}

    {% if office_active %}{% set workload.office = workload.office + 1 %}{% endif %}
    {% if email_active %}{% set workload.email = workload.email + 1 %}{% endif %}
    {% if teams_active %}{% set workload.teams = workload.teams + 1 %}{% endif %}
    {% if onedrive_active %}{% set workload.onedrive = workload.onedrive + 1 %}{% endif %}
    {% if sharepoint_active %}{% set workload.sharepoint = workload.sharepoint + 1 %}{% endif %}
    {% if m365app_active %}{% set workload.m365app = workload.m365app + 1 %}{% endif %}

    {% set workload_count = (1 if office_active else 0) + (1 if email_active else 0) + (1 if teams_active else 0) + (1 if onedrive_active else 0) + (1 if sharepoint_active else 0) + (1 if m365app_active else 0) %}
    {% set no_workload = licensed and (workload_count == 0) and not stale %}
    {% if no_workload %}{% set counters.no_workload = counters.no_workload + 1 %}{% endif %}

    {% set utilization_score = 0 %}
    {% if recent_signin %}{% set utilization_score = utilization_score + 18 %}{% endif %}
    {% if office_active %}{% set utilization_score = utilization_score + 22 %}{% endif %}
    {% if email_active %}{% set utilization_score = utilization_score + 12 %}{% endif %}
    {% if teams_active %}{% set utilization_score = utilization_score + 14 %}{% endif %}
    {% if onedrive_active %}{% set utilization_score = utilization_score + 10 %}{% endif %}
    {% if sharepoint_active %}{% set utilization_score = utilization_score + 12 %}{% endif %}
    {% if m365app_active %}{% set utilization_score = utilization_score + 12 %}{% endif %}
    {% if utilization_score > 100 %}{% set utilization_score = 100 %}{% endif %}

    {% if excluded_ref.value %}
        {% set classification = 'Excluded from scoring' %}
        {% set recommendation = 'Exclude from hygiene scoring or tag as service/shared account.' %}
    {% elif not licensed %}
        {% set classification = 'Unlicensed or not in scope' %}
        {% set recommendation = 'Confirm whether the user should remain in the tenant baseline.' %}
    {% elif stale %}
        {% set classification = 'Licensed and stale' %}
        {% set recommendation = 'Investigate disablement or reclaim assigned licenses.' %}
    {% elif no_workload and recent_signin %}
        {% set classification = 'Licensed, signs in, but no workload evidence' %}
        {% set recommendation = 'Review whether assigned products are oversized for the user.' %}
    {% elif workload_count <= 1 %}
        {% set classification = 'Licensed but low utilization' %}
        {% set recommendation = 'Check workload fit and consider license optimization.' %}
    {% else %}
        {% set classification = 'Licensed and active' %}
        {% set recommendation = 'Healthy usage footprint. Monitor normally.' %}
        {% set counters.active = counters.active + 1 %}
    {% endif %}
    {% if classification == 'Licensed but low utilization' %}{% set counters.low = counters.low + 1 %}{% endif %}
    {% if stale %}{% set priced_totals.stale_monthly = priced_totals.stale_monthly + cost_ref.monthly %}{% endif %}
    {% if classification == 'Licensed but low utilization' %}{% set priced_totals.low_monthly = priced_totals.low_monthly + cost_ref.monthly %}{% endif %}
    {% if classification == 'Licensed, signs in, but no workload evidence' %}{% set priced_totals.no_workload_monthly = priced_totals.no_workload_monthly + cost_ref.monthly %}{% endif %}

    {% set row = {
        'display_name': user.displayName | d('Unknown User'),
        'user_principal_name': user.userPrincipalName | d(user.mail) | d(''),
        'department': user.department | d(''),
        'job_title': user.jobTitle | d(''),
        'account_enabled': account_enabled,
        'licensed': licensed,
        'license_count': license_names | length,
        'license_names': license_names,
        'primary_license': license_names | first | d('Unlicensed'),
        'last_successful_signin': last_success,
        'recent_signin': recent_signin,
        'stale': stale,
        'excluded': excluded_ref.value,
        'office_active': office_active,
        'email_active': email_active,
        'teams_active': teams_active,
        'onedrive_active': onedrive_active,
        'sharepoint_active': sharepoint_active,
        'm365app_active': m365app_active,
        'workload_count': workload_count,
        'utilization_score': utilization_score,
        'classification': classification,
        'recommendation': recommendation,
        'assigned_plan_count': assigned_plans | length,
        'estimated_monthly_cost': cost_ref.monthly,
        'priced_licenses': cost_ref.priced_licenses,
        'unpriced_licenses': cost_ref.unpriced_licenses
    } %}
    {% set _ = data.user_rows.append(row) %}
    {% if stale %}{% set _ = data.stale_rows.append(row) %}{% endif %}
    {% if classification != 'Licensed and active' %}{% set _ = data.recommendation_rows.append(row) %}{% endif %}

    {% for license_name in license_names %}
        {% if license_name not in license_map %}
            {% set _ = license_map.update({license_name: {
                'license_name': license_name,
                'monthly_price': (price_map[license_name].monthly if license_name in price_map else none),
                'source': (price_map[license_name].source if license_name in price_map else 'Not priced'),
                'assigned_users': 0,
                'active_users': 0,
                'stale_users': [],
                'no_workload_users': 0,
                'excluded_users': 0,
                'total_monthly_cost': 0.0,
                'stale_monthly_cost': 0.0
            }}) %}
        {% endif %}
        {% set _ = license_map[license_name].update({'assigned_users': license_map[license_name].assigned_users + 1}) %}
        {% if license_name in price_map %}
            {% set _ = license_map[license_name].update({'total_monthly_cost': license_map[license_name].total_monthly_cost + price_map[license_name].monthly}) %}
        {% endif %}
        {% if classification == 'Licensed and active' %}
            {% set _ = license_map[license_name].update({'active_users': license_map[license_name].active_users + 1}) %}
        {% endif %}
        {% if stale %}
            {% set _ = license_map[license_name].stale_users.append({
                'display_name': row.display_name,
                'user_principal_name': row.user_principal_name,
                'last_successful_signin': row.last_successful_signin,
                'estimated_monthly_cost': row.estimated_monthly_cost,
                'monthly_price': (price_map[license_name].monthly if license_name in price_map else none)
            }) %}
            {% if license_name in price_map %}
                {% set _ = license_map[license_name].update({'stale_monthly_cost': license_map[license_name].stale_monthly_cost + price_map[license_name].monthly}) %}
            {% endif %}
        {% endif %}
        {% if no_workload %}
            {% set _ = license_map[license_name].update({'no_workload_users': license_map[license_name].no_workload_users + 1}) %}
        {% endif %}
        {% if excluded_ref.value %}
            {% set _ = license_map[license_name].update({'excluded_users': license_map[license_name].excluded_users + 1}) %}
        {% endif %}
    {% endfor %}
{% endfor %}

{% for license_name, record in license_map.items() %}
    {% set _ = data.license_rows.append(record) %}
{% endfor %}

{% set _ = data.update({
    'summary': {
        'total_users': counters.total,
        'enabled_users': counters.enabled,
        'licensed_users': counters.licensed,
        'active_users': counters.active,
        'low_utilization_users': counters.low,
        'stale_users': counters.stale,
        'no_workload_users': counters.no_workload,
        'excluded_users': counters.excluded,
        'unlicensed_users': counters.unlicensed
    },
    'pricing_summary': {
        'tenant_monthly_cost': priced_totals.monthly,
        'stale_monthly_reclaim': priced_totals.stale_monthly,
        'stale_annual_reclaim': priced_totals.stale_monthly * 12,
        'low_monthly_review': priced_totals.low_monthly,
        'no_workload_monthly_review': priced_totals.no_workload_monthly,
        'priced_assignment_count': priced_totals.priced_assignments,
        'total_assignment_count': priced_totals.total_assignments
    },
    'workload_summary': {
        'office': workload.office,
        'email': workload.email,
        'teams': workload.teams,
        'onedrive': workload.onedrive,
        'sharepoint': workload.sharepoint,
        'm365app': workload.m365app
    }
}) %}
{{- data | tojson -}}
